To display a QTextDocument with rich text content that is limited to a single line and does not wrap in a QStyledItemDelegate, you can set the document width to a very large value that makes it larger than the size of the item and set the text option to disable wrapping using the QTextOption class. Here is an example:

```
#include <QApplication>
#include <QListView>
#include <QStyledItemDelegate>
#include <QTextDocument>

class SingleLineDelegate : public QStyledItemDelegate
{
public:
    SingleLineDelegate(QObject* parent = nullptr) : QStyledItemDelegate(parent) {}

    void paint(QPainter *painter, const QStyleOptionViewItem &option, const QModelIndex &index) const override
    {
        // create a QTextDocument object
        QTextDocument doc;

        // set the rich text content of the document to a single line
        QString text = "<font color='red'>This is a single line QTextDocument with rich text content.</font>";
        doc.setHtml(text);

        // set the document width to a very large value
        doc.setTextWidth(option.rect.width() * 100);

        // create a QTextOption object and disable wrapping
        QTextOption opt;
        opt.setWrapMode(QTextOption::NoWrap);

        // set the text option of the QTextDocument
        doc.setDefaultTextOption(opt);

        // draw the text onto the item using the painter
        painter->save();
        painter->translate(option.rect.topLeft());
        doc.drawContents(painter);
        painter->restore();
    }
};

int main(int argc, char *argv[])
{
    QApplication app(argc, argv);

    // create a QListView object
    QListView view;

    // set the item delegate to our custom delegate
    view.setItemDelegate(new SingleLineDelegate(&view));

    // add an item to the list view and set its data
    QStringListModel model;
    model.setStringList(QStringList() << "Item 1");
    view.setModel(&model);
    view.show();

    return app.exec();
}
```

In this example, we create a custom QStyledItemDelegate that sets the rich text content of the QTextDocument to a single line and disables wrapping using QTextOption. We set the document width to a very large value that makes it larger than the size of the item using setTextWidth(). Finally, we draw the text onto the item using the painter and the drawContents() method of the QTextDocument. When the delegate is applied to the item in the QListView, it draws the rich text content as a single line that does not wrap.

